import React from 'react';

export default function TypingIndicator() {
  return (
    <div className="flex items-center justify-center p-4">
      {/* 
        - Removed background color (bg-transparent or default)
        - Used border-4 for a thicker, more visible connected border
        - Used border-t-[#ff5e4d] (or project primary color) for the spinner effect
        - Used border-white/10 for the rest of the circle to keep it subtle but connected
        - rounded-full ensures it is a perfect circle
        - animate-spin handles the rotation
      */}
      <div 
        className="h-8 w-8 border-4 border-white/10 border-t-[#ff5e4d] rounded-full animate-spin"
        role="status"
        aria-label="Loading"
      />
      <span className="sr-only">Loading...</span>
    </div>
  );
}
